test.config:
indexer
{
	mem_limit = 16M
}

searchd
{

}

source srctest
{
	type = mysql

	sql_query = SELECT id, content FROM test_table
}

index test
{
	source = srctest
	path = /test
	index_field_lengths = 1
}

test.db_create:
CREATE TABLE test_table
(
	id INTEGER PRIMARY KEY NOT NULL,
	content VARCHAR(1024) NOT NULL
);
